// File: tests/pages/BasePage.ts
import { Page, Locator } from '@playwright/test';

export class BasePage {
  protected page: Page;

  constructor(page: Page) {
    this.page = page;
  }

  async goto(path: string): Promise<void> {
    await this.page.goto(path);
  }

  async clickElement(locator: Locator): Promise<void> {
    await locator.waitFor({ state: 'visible' });
    await locator.click();
  }

  async fillInput(locator: Locator, value: string): Promise<void> {
    await locator.fill(value);
  }
}

// File: tests/components/BaseComponent.ts
import { Page, Locator } from '@playwright/test';

export class BaseComponent {
  protected page: Page;
  protected container: Locator;

  constructor(page: Page, selector?: string) {
    this.page = page;
    this.container = selector ? page.locator(selector) : page.locator('body');
  }

  async clickInside(locator: Locator): Promise<void> {
    await locator.click();
  }
}

